/***** VA → Airtable updater (Audits ALL records with conditional logic) *****/
const rec = $input.item?.json ?? {};
const id  = typeof rec.id === "string" ? rec.id.trim() : "";

// Helper to get field values safely
const get = (name) => rec[name] !== undefined ? rec[name] : rec.fields?.[name];

// 🟢 MODIFIED Helper: Checks if value is empty OR "to follow"
const isEmpty = (v) => {
  if (v == null) return true;
  if (Array.isArray(v)) return v.length === 0;
  if (typeof v === "string") {
    const s = v.trim();
    // Returns true if empty OR if it equals "to follow" (ignoring case)
    return s === "" || s.toLowerCase() === "to follow";
  }
  return false;
};

// 1. Safety Check
if (!id) return { json: { _skip: true, reason: "missing id", sourceIndex: $itemIndex } };

// 🔍 List of fields to audit
const CHECK_FIELDS = [
  "VA Source",
  "VA Status",
  "Endorsed to Placements",
  "SV Base Rate",
  "Intro Video",
  "Resume [Link]",
  "PI - Behavioral [Link]",
  "PI - Cognitive [Link]",
  "DISC [Link]",
  "Personal Email",
  "SV Email",        // <--- Logic #1 applies here
  "Phone Number",
  "Photo",
];

// 🧠 LOGIC #1: Check for Client History
const clientHistory = get("Client History");
const hasClientHistory = !isEmpty(clientHistory); // Note: "to follow" in history would now count as missing too

let missing = [];

// 🧮 Loop through and check missing fields
for (const field of CHECK_FIELDS) {

  // START LOGIC #1 ---------------------------
  // If we are checking "SV Email", BUT there is no Client History... skip it.
  if (field === "SV Email" && !hasClientHistory) {
    continue; 
  }
  // END LOGIC #1 -----------------------------

  if (isEmpty(get(field))) {
    missing.push(field);
  }
}

// 🧾 Build update object
const fields = {
  "For Scrubbing?": missing.length > 0,
  "Fields with Missing Data": missing.join(", "),
  "Last Scrubbed At": new Date().toISOString(),
};

return { json: { id, fields } };

/***** VA → Airtable updater (Each Item, empties-only) *****/
const rec = $input.item?.json ?? {};
const id  = typeof rec.id === "string" ? rec.id.trim() : "";
const get = (name) => rec[name] !== undefined ? rec[name] : rec.fields?.[name];
const isEmpty = (v) => v == null ? true : Array.isArray(v) ? v.length === 0 : (typeof v === "string" ? v.trim() === "" : false);

if (!id) return { json: { _skip: true, reason: "missing id", sourceIndex: $itemIndex } };

const CHECK_FIELDS = [
  "PL STAGE",
  "Clients",
  "PDEV Requirement",
  "Company",
  "REQUIRED MVA",
  "Full/Part Time",
  "PLACEMENT TYPE",
  "Initial Client Rate",
  "JD + C",
];

const missing = CHECK_FIELDS.filter((name) => isEmpty(get(name)));

const fields = {
  "For Scrubbing?": missing.length > 0,
  "Fields with Missing Data": missing.join(", "),
  "Last Scrubbed At": new Date().toISOString(),
};

return { json: { id, fields } };

/***** Aggregate Metrics — Daily Scrubbing row (adds hyperlink JSON) *****
 * Place: after the Loop node (from the Loop's "done" port)
 * LOOKUP_NODE: your search node (has primary names)
 ******************************************************************************/

const LOOKUP_NODE = "Search Virtual Assistants";   // search for this branch
const TABLE_NAME  = "Virtual Assistants";          
const PRIMARY_NAME_FIELD = "Virtual Assistant";    

// ---------- gather inputs (FIXED) ----------
// We use $input.all() because the "Loop VA" node is already 
// feeding all 62 items directly into this node.
const detectorItems = $input.all(); 

// We still look up the names separately
const lookupItems   = $(LOOKUP_NODE).all(); 
const scanned = detectorItems.length;

// ---------- build ID→Name map from lookup results ----------
const nameById = new Map();
for (const it of lookupItems) {
  const j  = it.json || {};
  const id = String(j.id || j.recordId || j?.fields?.id || "").trim();
  const nm = j?.fields?.[PRIMARY_NAME_FIELD] ?? j[PRIMARY_NAME_FIELD] ?? j?.fields?.name ?? j.name;
  if (id && nm) nameById.set(id, String(nm).trim());
}

// ---------- tally + per-record capture ----------
let flagged = 0;
let forScrubbingCount = 0;
const tally = Object.create(null);
const perRecord = [];
const alias = (s) => String(s).replace(/\s*\[Link\]\s*$/i, "");

for (const it of detectorItems) {
  const j = it.json || {};
  const f = j.fields || {};
  const id = String(j.id || j.recordId || j?.fields?.id || "").trim();

  // FIX: Ensure we check the boolean correctly, treating text "true" as true if needed
  if (f["For Scrubbing?"] === true || f["For Scrubbing?"] === "true") {
    flagged++;
    forScrubbingCount++;
  }

  const list = String(f["Fields with Missing Data"] || "")
    .split(/[,\n;]+/)
    .map(s => alias(s.trim()))
    .filter(Boolean);

  const seen = new Set();
  const missing = [];
  for (const key of list) {
    if (!seen.has(key)) {
      seen.add(key);
      missing.push(key);
      tally[key] = (tally[key] || 0) + 1;
    }
  }

  // If we found missing fields, add to the record list
  if (missing.length) {
    perRecord.push({
      id,
      name: nameById.get(id) || "(No name)",
      missing,
      missing_count: missing.length,
    });
  }
}

// ---------- global top-missing fields ----------
const top_missing_json = Object.entries(tally)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

// ---------- pick top records for the human string + JSON helpers ----------
perRecord.sort((a, b) => (b.missing_count - a.missing_count) || a.name.localeCompare(b.name));

const TOP_N = 5;
const MAX_FIELDS_PER_LINE = 5;

const topRecords = perRecord.slice(0, TOP_N);

// human lines
const lines = topRecords.map(r => {
  const shown = r.missing.slice(0, MAX_FIELDS_PER_LINE);
  const extra = r.missing.length - shown.length;
  return `• ${r.name} — ${shown.join(", ")}${extra > 0 ? `, +${extra} more` : ""}`;
});

// machine helpers for hyperlinks
const nameIdMap = {};
const topNames  = [];
const topIds    = [];
const topRecordsSlim = []; 

for (const r of topRecords) {
  if (r.name && r.id) nameIdMap[r.name] = r.id;
  topNames.push(r.name);
  topIds.push(r.id);
  topRecordsSlim.push({
    id: r.id,
    name: r.name,
    missing: r.missing,
    missing_count: r.missing_count,
  });
}

// ---------- final payload ----------
const humanBlock = lines.join("\n") + (lines.length ? "\n" : "");

return [{
  json: {
    table: TABLE_NAME,
    date_scrubbed: new Date().toISOString(),
    run_id: $json.run_id || (Date.now().toString(36) + Math.random().toString(36).slice(2,8)),
    scanned,
    flagged,
    cleared: 0,
    for_scrubbing_count: forScrubbingCount,
    top_missing_json,

    // Human-friendly strings
    display_missing_records: humanBlock,
    display_missing_fields:  humanBlock,            

    // Structured (optional) for debugging/analytics
    display_missing_records_lines: lines,
    display_missing_records_json:  topRecordsSlim,

    // 🔗 Hyperlink helpers
    "Top Records (JSON)":   JSON.stringify(topRecordsSlim),
    "Name→ID Map (JSON)":   JSON.stringify(nameIdMap),
    "Top Record IDs (JSON)":  JSON.stringify(topIds),
    "Top Names (JSON)":     JSON.stringify(topNames),
  }
}];

/**
 * US/Sunday-start week labels in PHT, with table initials appended.
 * Example week_label: "2025-W42-VA"
 */

const agg = items[0]?.json ?? {};

// ---------- helpers (PHT) ----------
const pad = (n) => String(n).padStart(2, '0');
const toPHT = (d) => {
  const utcMs = d.getTime() + d.getTimezoneOffset() * 60000;
  return new Date(utcMs + 8 * 3600000); // UTC+8
};
const sundayStartPHT = (dPHT) => {
  const x = new Date(dPHT);
  const dow = x.getDay(); // Sun=0..Sat=6
  x.setDate(x.getDate() - dow); // rewind to Sunday
  x.setHours(0,0,0,0);
  return x;
};
const yyyymmddNum = (d) =>
  Number(`${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}`);

/** US-style week label (Sunday-start, Jan-1 rule), e.g. 2025-W42 */
const weekLabelUS = (dPHT) => {
  const year = dPHT.getFullYear();
  const jan1 = new Date(year, 0, 1);
  jan1.setHours(0,0,0,0);
  const jan1PHT = toPHT(jan1);
  const days = Math.floor((dPHT - jan1PHT) / 86400000);
  const week = Math.floor((days + jan1PHT.getDay()) / 7) + 1;
  return `${year}-W${String(week).padStart(2, '0')}`;
};

/** Derive initials for the table (with a few explicit mappings) */
const tableInitials = (name) => {
  const map = {
    'Virtual Assistants': 'VA',
    'Placements Requirements': 'PR',
    'PDEV Requirements': 'PDEV',
    'PDEV Ongoing Requirements': 'PDEV',
  };
  if (map[name]) return map[name];

  // Generic fallback: take first letters of words, up to 6 chars
  const words = String(name || '')
    .split(/[^A-Za-z0-9]+/)
    .filter(Boolean);
  if (words.length === 0) return 'GEN';

  // If it's already an acronym like "PDEV" or "VA", keep it
  const allCaps = words.join('').match(/^[A-Z0-9]{2,}$/);
  if (allCaps) return allCaps[0].slice(0, 6);

  return words.map(w => w[0].toUpperCase()).join('').slice(0, 6);
};

